                            type="button"
                            onClick={() => setLoginMethod("email")}
                            className={`flex-1 py-2 text-sm font-medium rounded-lg transition-colors ${loginMethod === "email" ? "bg-primary text-white shadow-lg" : "text-gray-400 hover:text-white"
